class Solution:
    def solve(self, s1: str, s2: str) -> str:
        if s1 is None:
            return s2
        elif s2 is None:
            return s1
        else:
            return s1 + s2

def main():
    solution = Solution()
    s1 = input()
    s2 = input()
    print(solution.solve(s1, s2))
if __name__ == '__main__':
    main()

