class Solution {
public:
    string solve(string s1, string s2) {
        if (s1.empty()) {
            return s2;
        } else if (s2.empty()) {
            return s1;
        } else {
            return s1 + s2;
        }
    }
};

int main() {
    Solution solution;
    string s1, s2;
    cin >> s1 >> s2;
    cout << solution.solve(s1, s2) << endl;
    return 0;
}
